Here's an example C# program for a game of Snake. Note that this is just an example and can be customized to fit your needs.

```
using System;
using System.Collections.Generic;

class Program {
    static void Main(string[] args) {
        Console.SetWindowSize(Console.WindowWidth+1, Console.WindowHeight+1);
        Console.SetBufferSize(Console.WindowWidth+1, Console.WindowHeight+1);

        int score = 0;
        bool gameOver = false;
        int xMax = Console.WindowWidth-15;
        int yMax = Console.WindowHeight-1;
        Random random = new Random();

        List<int> xSnake = new List<int>();
        List<int> ySnake = new List<int>();

        int xFood = random.Next(1, xMax);
        int yFood = random.Next(1, yMax);

        xSnake.Insert(0, xMax/2);
        ySnake.Insert(0, yMax/2);

        while (!gameOver) {
            while (Console.KeyAvailable) {
                ConsoleKeyInfo key = Console.ReadKey(true);
                switch (key.Key) {
                    case ConsoleKey.LeftArrow:
                        xSnake[0]--;
                        break;
                    case ConsoleKey.RightArrow:
                        xSnake[0]++;
                        break;
                    case ConsoleKey.UpArrow:
                        ySnake[0]--;
                        break;
                    case ConsoleKey.DownArrow:
                        ySnake[0]++;
                        break;
                }
            }

            if (xSnake[0] == xFood && ySnake[0] == yFood) {
                score++;
                xFood = random.Next(1, xMax);
                yFood = random.Next(1, yMax);
            } else {
                xSnake.RemoveAt(xSnake.Count-1);
                ySnake.RemoveAt(ySnake.Count-1);
            }
            if (xSnake[0] < 1 || xSnake[0] >= xMax || ySnake[0] < 1 || ySnake[0] >= yMax) {
                gameOver = true;
            }
            for (int i = 1; i < xSnake.Count; i++) {
                if (xSnake[0] == xSnake[i] && ySnake[0] == ySnake[i]) {
                    gameOver = true;
                }
            }

            xSnake.Insert(0, xSnake[0]);
            ySnake.Insert(0, ySnake[0]);

            Console.Clear();
            Console.SetCursorPosition(xFood, yFood);
            Console.Write("O");
            for (int i = 0; i < xSnake.Count; i++) {
                Console.SetCursorPosition(xSnake[i], ySnake[i]);
                Console.Write("X");
            }
            Console.SetCursorPosition(0, yMax+1);
            Console.WriteLine("Score: {0}", score);

            System.Threading.Thread.Sleep(100);
        }

        Console.Clear();
        Console.SetCursorPosition(0,0);
        Console.WriteLine("Game over! Your score was {0}", score);
        Console.ReadLine();
    }
}
```


This example game of Snake uses the console to display the game board and handle user input. The snake is represented by a series of X's and the food is represented by an O. The game ends when the snake collides with the walls or itself.
